THOUGHT: The crash indicates LICM is cloning an instruction into the exit block and unconditionally creating a MemorySSA access for it, but the instruction doesn’t touch memory (per MemorySSA), triggering the assertion. We need to modify LICM.cpp’s cloneInstructionInExitBlock to only create a MemorySSA access when the cloned instruction is memory-touching. I’ll inspect the file, implement a guard using MemorySSA’s helper to detect interesting memory opcodes, and run submit-patch to validate.

```bash
nl -ba llvm/lib/Transforms/Scalar/LICM.cpp | sed -n '1400,1560p' && sed -n '1,200p' llvm/lib/Analysis/MemorySSA.cpp | sed -n '1680,1760p' && python3 - << 'PY'
import re, sys, subprocess, textwrap, os
path = "llvm/lib/Transforms/Scalar/LICM.cpp"
with open(path, 'r') as f:
    s = f.read()
# Insert guard in cloneInstructionInExitBlock around MemorySSAUpdater.createMemoryAccessInBB
pattern = r'(MemorySSAUpdater\s*&\s*MSSAU\)\s*\{\s*(?:.|\n)*?Instruction\s*\*\s*ClonedI\s*=\s*[^;]+;)([\s\S]*?)\n\s*MSSAU\.createMemoryAccessInBB\(\s*ClonedI,\s*NewMemAcc,\s*&ExitBlock,\s*MemorySSA::InsertionPlace::End\s*\)\s*;'
m = re.search(pattern, s)
if not m:
    print("Could not locate createMemoryAccessInBB in cloneInstructionInExitBlock", file=sys.stderr)
    sys.exit(1)
before = m.group(0)
guard = textwrap.dedent('''
  // Only create MemorySSA access for memory-touching instructions.
  auto IsInterestingMemOp = [](const Instruction *I) {
    using namespace llvm;
    // MemorySSA tracks loads, stores, volatile ops, and calls/invokes that may access memory.
    // Use MemorySSA::isInterestingMemoryOpcode via opcode check, and query MemoryEffects for calls.
    unsigned Op = I->getOpcode();
    switch (Op) {
    case Instruction::Load:
    case Instruction::Store:
    case Instruction::VAArg:
    case Instruction::AtomicCmpXchg:
    case Instruction::AtomicRMW:
    case Instruction::Fence:
      return true;
    case Instruction::Call:
    case Instruction::Invoke: {
      // Query memory effects; if memory(none), skip creating an access.
      const auto &ME = MemoryEffects::unknown();
      if (const auto *CB = dyn_cast<CallBase>(I)) {
        auto Effects = CB->getMemoryEffects();
        return !Effects.onlyReadsMemory() || !Effects.doesNotAccessMemory();
      }
      return true;
    }
    default:
      return false;
    }
  };
  if (IsInterestingMemOp(ClonedI)) {
    MSSAU.createMemoryAccessInBB(ClonedI, NewMemAcc, &ExitBlock, MemorySSA::InsertionPlace::End);
  }
''').strip()
after = re.sub(r'\n\s*MSSAU\.createMemoryAccessInBB\(\s*ClonedI,\s*NewMemAcc,\s*&ExitBlock,\s*MemorySSA::InsertionPlace::End\s*\)\s*;', "\n  " + guard, before, count=1)
s2 = s.replace(before, after)
with open(path, 'w') as f:
    f.write(s2)
print("Patched LICM.cpp")
PY
 && ninja -C llvm-autofix/build/llvm-build/116809 opt && /llvm-autofix/build/llvm-build/116809/bin/opt -passes=loop-mssa(simple-loop-unswitch<nontrivial>,licm) -verify-memoryssa -S /tmp/test.ll && submit-patch
```

